WITH "years" AS (SELECT 2013 AS "year" UNION ALL SELECT 2014), "statuses" AS (SELECT 'active' AS "status" UNION ALL SELECT 'closed'), "stations_with_year" AS ( SELECT EXTRACT(YEAR FROM TO_TIMESTAMP("modified_date" / 1000000)) AS "year", LOWER("status") AS "status", "station_id" FROM "AUSTIN"."AUSTIN_BIKESHARE"."BIKESHARE_STATIONS" WHERE LOWER("status") IN ('active', 'closed') ), "counts" AS ( SELECT "year", "status", COUNT(DISTINCT "station_id") AS "station_count" FROM "stations_with_year" WHERE "year" IN (2013, 2014) GROUP BY "year", "status" ) SELECT "y"."year", "s"."status", COALESCE("c"."station_count", 0) AS "station_count" FROM "years" "y" CROSS JOIN "statuses" "s" LEFT JOIN "counts" "c" ON "y"."year" = "c"."year" AND "s"."status" = "c"."status" ORDER BY "y"."year", "s"."status"